#[test]
fn tblprex_jc_before_shd_ct_tblprexbase_order() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tblPrEx><w:jc w:val="start"/><w:shd w:val="clear" w:color="auto" w:fill="EEECE1" w:themeFill="background2"/></w:tblPrEx><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "jc-then-shd inside tblPrEx is the exact CT_TblPrExBase sequence; doc must open clean \
         (ISO 29500-1 §17.4.30/§17.4.60; ECMA-376 Annex A CT_TblPrExBase; §17.3.5)",
    );

    let xml = reserialize(&b);
    // xmlRegex: <w:tblPrEx>.*<w:jc[^>]*/>.*<w:shd[^>]*/>.*</w:tblPrEx>
    assert!(
        contains_in_order(
            &xml,
            &["<w:tblPrEx>", "<w:jc", "/>", "<w:shd", "/>", "</w:tblPrEx>"]
        ),
        "CT_TblPrExBase orders jc (pos 2) before shd (pos 6); serializer must emit jc before shd \
         in tblPrEx (ISO 29500-1 §17.4.30/§17.4.60; ECMA-376 Annex A CT_TblPrExBase). Got: {xml}"
    );
}

#[test]
fn tblprexchange_serializes_last_in_tblprex() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tblPrEx><w:tblBorders><w:top w:val="single" w:sz="4" w:space="0" w:color="auto"/></w:tblBorders><w:tblPrExChange w:id="9" w:author="A" w:date="2021-01-01T00:00:00Z"><w:tblPrEx><w:tblBorders><w:top w:val="single" w:sz="4" w:space="0" w:color="FF0000"/></w:tblBorders></w:tblPrEx></w:tblPrExChange></w:tblPrEx><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "tblBorders followed by a trailing tblPrExChange is the exact CT_TblPrEx content model; \
         doc must open clean (ISO 29500-1 §17.4.61; ECMA-376 Annex A CT_TblPrEx/CT_TblPrExBase)",
    );

    let xml = reserialize(&b);
    // xmlRegex: <w:tblBorders>.*</w:tblBorders>.*<w:tblPrExChange
    assert!(
        contains_in_order(
            &xml,
            &["<w:tblBorders>", "</w:tblBorders>", "<w:tblPrExChange"]
        ),
        "CT_TblPrEx appends tblPrExChange after the base property children; serializer must emit \
         live tblBorders before the trailing tblPrExChange (ISO 29500-1 §17.4.61; ECMA-376 Annex A \
         CT_TblPrEx/CT_TblPrExBase). Got: {xml}"
    );
}

#[test]
fn table_cell_shd_themefill_retained_roundtrip() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:shd w:val="clear" w:color="auto" w:fill="C3D69B" w:themeFill="accent3"/></w:tcPr><w:p><w:r><w:t>Cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "A cell shd with val/color/fill/themeFill is a valid CT_Shd; doc must open clean \
         (ISO 29500-1 §17.4.32/§17.3.5; ECMA-376 Annex A CT_Shd; §17.18.97 ST_ThemeColor)",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:themeFill="accent3""#),
        "themeFill supersedes the literal fill; serializer must retain it on round-trip or the \
         cell color changes (ISO 29500-1 §17.4.32/§17.3.5; ECMA-376 Annex A CT_Shd). Got: {xml}"
    );
}

#[test]
fn table_level_shd_nil_ignored_text_survives() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/><w:shd w:val="nil"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Shaded text</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "Table-level shd val=nil is a valid CT_Shd on tblPr; doc must open clean \
         (ISO 29500-1 §17.4.31/§17.18.78; MS-OI29500 §2.1.59)",
    );

    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "Shaded text",
        "Shading is display-only; nil shading must not alter cell text, so accepted read text \
         equals the authored text (ISO 29500-1 §17.4.31/§17.18.78)"
    );
    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "Shaded text",
        "shd is not a tracked change; rejecting changes nothing, so rejected read text equals \
         the authored text (ISO 29500-1 §17.4.31/§17.18.78)"
    );
}

