#[test]
fn tblprex_shd_after_tblborders_order() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tblPrEx><w:tblBorders><w:top w:val="single" w:sz="4" w:space="0" w:color="auto"/></w:tblBorders><w:shd w:val="clear" w:color="auto" w:fill="FF0000"/></w:tblPrEx><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Row one</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    // xmlRegex: <w:tblPrEx>.*<w:tblBorders>.*</w:tblBorders>.*<w:shd[^>]*/>.*</w:tblPrEx>
    assert!(
        contains_in_order(
            &xml,
            &[
                "<w:tblPrEx>",
                "<w:tblBorders>",
                "</w:tblBorders>",
                "<w:shd",
                "/>",
                "</w:tblPrEx>",
            ]
        ),
        "CT_TblPrExBase mandates tblBorders before shd; serialized tblPrEx must keep that schema \
         order (ISO 29500-1 §A.1 CT_TblPrExBase/§17.4.60/§17.4.30). Got: {xml}"
    );

    assert_opens_clean(
        &b,
        "A tblPrEx whose children follow CT_TblPrExBase order is schema-valid and Word opens it \
         without repair (ISO 29500-1 §A.1 CT_TblPrExBase/§17.4.60/§17.4.30)",
    );
}

