#[test]
fn table_level_shd_superseded_by_cell_shd_is_consumption() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/><w:shd w:val="clear" w:color="auto" w:fill="00FF00"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:shd w:val="clear" w:color="auto" w:fill="FF0000"/></w:tcPr><w:p><w:r><w:t>Shaded</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accepted.trim(),
        "Shaded",
        "Table shd is superseded background only and carries no content; consuming the cell yields \
         exactly the authored text (ISO 29500-1 §17.4.31/§17.4.32)"
    );
    let rejected = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        rejected.trim(),
        "Shaded",
        "shd is not a tracked change, so reject must yield the same text as accept \
         (ISO 29500-1 §17.4.31/§17.4.32)"
    );

    assert_opens_clean(
        &b,
        "A clear/color/fill shd at both table and cell level is the Word-valid shading form and \
         opens without repair (ISO 29500-1 §17.4.31/§17.4.32)",
    );
}

